{
  "name": "UzGer Lexicon (LEX.)",
  "description": "A sophisticated, scholarly translation engine supporting German, Uzbek, English, and Russian with CEFR tracking and literary context.",
  "requestFramePermissions": [
    "microphone"
  ]
}

export type Language = 'German' | 'Uzbek' | 'English' | 'Russian';

export interface LexicalEntry {
  id: string;
  sourceWord: string;
  sourceLang: Language;
  targetWord: string;
  targetLang: Language;
  partOfSpeech: string;
  gender?: string; // German specific
  plural?: string;
  phoneticSource: string;
  phoneticTarget: string;
  cefrSource?: string; // Hidden for Uzbek
  cefrTarget?: string; // Hidden for Uzbek
  annotations: string;
  synonyms: string[];
  examples: Array<{
    text: string;
    translation: string;
    context: string; // "Literary Source" or "Cinematic Context"
  }>;
  timestamp: number;
}

export interface UserProfile {
  username: string;
  xp: number;
  rank: string;
  searchCount: number;
  arenaWins: number;
}

export enum AppMode {
  DICTIONARY = 'DICTIONARY',
  ARENA = 'ARENA',
  ARCHIVE = 'ARCHIVE'
}

import { Language } from './types';

export const VOICE_MAPPING: Record<Language, string> = {
  German: 'Kore',
  Uzbek: 'Zephyr',
  English: 'Puck',
  Russian: 'Charon',
};

export const RANKS = [
  { minXp: 0, title: 'Lexical Novice' },
  { minXp: 500, title: 'Archive Scribe' },
  { minXp: 1500, title: 'Polyglot Scholar' },
  { minXp: 4000, title: 'Etymological Dean' },
  { minXp: 10000, title: 'The Lexicon Master' },
];

export const APP_ACCENT = '#7c1a1a';

import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function translateWord(
  word: string, 
  sourceLang: Language, 
  targetLang: Language
): Promise<LexicalEntry> {
  const prompt = `Translate the word "${word}" from ${sourceLang} to ${targetLang}. 
    Provide comprehensive linguistic data including CEFR level, phonetic spelling, part of speech, 
    and plural forms. If the target is German, include gender. 
    Provide three high-quality example sentences with citations like "Literary Source: Goethe" or "Cinematic Context: Inception". 
    Format synonyms as a simple array.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          targetWord: { type: Type.STRING },
          partOfSpeech: { type: Type.STRING },
          gender: { type: Type.STRING, description: 'Only for German' },
          plural: { type: Type.STRING },
          phoneticSource: { type: Type.STRING },
          phoneticTarget: { type: Type.STRING },
          cefrSource: { type: Type.STRING, description: 'e.g. A1, B2' },
          cefrTarget: { type: Type.STRING },
          annotations: { type: Type.STRING },
          synonyms: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          },
          examples: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                translation: { type: Type.STRING },
                context: { type: Type.STRING }
              },
              required: ["text", "translation", "context"]
            }
          }
        },
        required: ["targetWord", "partOfSpeech", "phoneticSource", "phoneticTarget", "cefrSource", "cefrTarget", "annotations", "synonyms", "examples"]
      }
    }
  });

  const rawData = JSON.parse(response.text);

  return {
    id: crypto.randomUUID(),
    sourceWord: word,
    sourceLang,
    targetWord: rawData.targetWord,
    targetLang,
    partOfSpeech: rawData.partOfSpeech,
    gender: rawData.gender,
    plural: rawData.plural,
    phoneticSource: rawData.phoneticSource,
    phoneticTarget: rawData.phoneticTarget,
    cefrSource: rawData.cefrSource,
    cefrTarget: rawData.cefrTarget,
    annotations: rawData.annotations,
    synonyms: rawData.synonyms,
    examples: rawData.examples,
    timestamp: Date.now()
  };
}

export async function generateQuiz(entries: LexicalEntry[]) {
  const words = entries.map(e => `${e.sourceWord} -> ${e.targetWord}`).join(", ");
  const prompt = `Based on these translations: ${words}, generate 5 multiple choice questions to test vocabulary.
    Include one correct answer and three distractors for each.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            correctAnswer: { type: Type.STRING },
            options: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            explanation: { type: Type.STRING }
          },
          required: ["question", "correctAnswer", "options", "explanation"]
        }
      }
    }
  });

  return JSON.parse(response.text);
}

import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";
import { VOICE_MAPPING } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Utility to decode base64 to Uint8Array (required for raw PCM)
function decode(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Utility to decode PCM to AudioBuffer
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export async function speak(text: string, lang: Language) {
  try {
    const voiceName = VOICE_MAPPING[lang] || 'Puck';
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      audioCtx,
      24000,
      1
    );

    const source = audioCtx.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(audioCtx.destination);
    source.start();
  } catch (error) {
    console.error("TTS Failed:", error);
  }
}

import React from 'react';
import { UserProfile } from '../types';
import { RANKS } from '../constants';

interface Props {
  profile: UserProfile;
}

const XPProgress: React.FC<Props> = ({ profile }) => {
  const currentRank = RANKS.findLast(r => profile.xp >= r.minXp) || RANKS[0];
  const nextRank = RANKS[RANKS.indexOf(currentRank) + 1];

  const progress = nextRank 
    ? ((profile.xp - currentRank.minXp) / (nextRank.minXp - currentRank.minXp)) * 100
    : 100;

  return (
    <div className="w-full bg-stone-200 border border-stone-300 p-4 mb-8">
      <div className="flex justify-between items-end mb-2">
        <div>
          <span className="text-xs uppercase tracking-widest text-stone-500 font-bold">Lexical Ranking</span>
          <h2 className="text-2xl serif font-bold text-stone-900">{currentRank.title}</h2>
        </div>
        <div className="text-right">
          <span className="text-sm font-mono text-[#7c1a1a] font-bold">{profile.xp} XP</span>
        </div>
      </div>
      <div className="w-full h-1 bg-stone-300 relative">
        <div 
          className="absolute top-0 left-0 h-full bg-[#7c1a1a] transition-all duration-1000"
          style={{ width: `${progress}%` }}
        />
      </div>
      {nextRank && (
        <p className="text-[10px] text-stone-400 mt-2 uppercase tracking-tighter">
          {nextRank.minXp - profile.xp} XP until {nextRank.title}
        </p>
      )}
    </div>
  );
};

export default XPProgress;

