import React, { useState, useEffect } from 'react';
import { Language, LexicalEntry } from '../types';
import { translateWord } from '../services/gemini';
import { speak } from '../services/tts';
import ResultCard from './ResultCard';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
}

const LANGUAGES: Language[] = ['German', 'Uzbek', 'English', 'Russian'];

const Dictionary: React.FC<Props> = ({ onEntrySaved, autoAudio }) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setResult(null);
    try {
      const entry = await translateWord(query, sourceLang, targetLang);
      setResult(entry);
      onEntrySaved(entry);
      if (autoAudio) {
        speak(entry.targetWord, entry.targetLang);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const swapLangs = () => {
    setSourceLang(targetLang);
    setTargetLang(sourceLang);
  };

  return (
    <div className="max-w-4xl mx-auto py-12 px-4">
      <div className="text-center mb-12">
        <h1 className="text-7xl font-bold tracking-tighter text-stone-900 mb-2">LEX<span className="text-[#7c1a1a]">.</span></h1>
        <p className="serif italic text-stone-500">The Polyglot Insight Engine</p>
      </div>

      <form onSubmit={handleSearch} className="mb-12">
        <div className="flex flex-col md:flex-row gap-4 items-center justify-center mb-6 text-sm font-medium uppercase tracking-widest text-stone-500">
          <select 
            value={sourceLang} 
            onChange={(e) => setSourceLang(e.target.value as Language)}
            className="bg-transparent border-b border-stone-300 py-1 focus:border-[#7c1a1a] outline-none transition-colors"
          >
            {LANGUAGES.map(l => <option key={l} value={l}>{l}</option>)}
          </select>
          <button type="button" onClick={swapLangs} className="p-2 hover:bg-stone-200 rounded-full transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m7 15 5 5 5-5"/><path d="m7 9 5-5 5 5"/></svg>
          </button>
          <select 
            value={targetLang} 
            onChange={(e) => setTargetLang(e.target.value as Language)}
            className="bg-transparent border-b border-stone-300 py-1 focus:border-[#7c1a1a] outline-none transition-colors"
          >
            {LANGUAGES.map(l => <option key={l} value={l}>{l}</option>)}
          </select>
        </div>

        <div className="relative group max-w-2xl mx-auto">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search the archive..."
            className="w-full text-4xl serif bg-white border border-stone-300 py-6 px-10 focus:border-[#7c1a1a] outline-none shadow-sm transition-all"
          />
          <button 
            type="submit"
            disabled={loading}
            className="absolute right-6 top-1/2 -translate-y-1/2 text-stone-400 group-hover:text-[#7c1a1a] transition-colors"
          >
            {loading ? (
              <div className="w-8 h-8 border-2 border-[#7c1a1a] border-t-transparent rounded-full animate-spin" />
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
            )}
          </button>
        </div>
      </form>

      {result && <ResultCard entry={result} />}

      {!result && !loading && (
        <div className="text-center py-20 opacity-20 select-none">
          <svg className="mx-auto mb-4" xmlns="http://www.w3.org/2000/svg" width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z"/><path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z"/></svg>
          <p className="serif text-xl">The pages are waiting to be turned.</p>
        </div>
      )}
    </div>
  );
};

export default Dictionary;

import React, { useState, useEffect } from 'react';
import { LexicalEntry, UserProfile } from '../types';
import { generateQuiz } from '../services/gemini';

interface Props {
  history: LexicalEntry[];
  onResult: (won: boolean) => void;
}

interface Question {
  question: string;
  correctAnswer: string;
  options: string[];
  explanation: string;
}

const Arena: React.FC<Props> = ({ history, onResult }) => {
  const [questions, setQuestions] = useState<Question[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [score, setScore] = useState(0);
  const [loading, setLoading] = useState(true);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [revelation, setRevelation] = useState(false);
  const [finished, setFinished] = useState(false);

  useEffect(() => {
    const loadQuiz = async () => {
      if (history.length < 3) {
        // Fallback for empty history
        setLoading(false);
        return;
      }
      try {
        const data = await generateQuiz(history.slice(0, 10));
        setQuestions(data);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    loadQuiz();
  }, [history]);

  const handleOptionSelect = (option: string) => {
    if (revelation) return;

    setSelectedOption(option);
    setRevelation(true);

    const isCorrect = option === questions[currentIdx].correctAnswer;
    if (isCorrect) setScore(s => s + 1);

    // Haptic feedback if in Telegram
    if ((window as any).Telegram?.WebApp) {
      (window as any).Telegram.WebApp.HapticFeedback.notificationOccurred(isCorrect ? 'success' : 'error');
    }
  };

  const nextQuestion = () => {
    if (currentIdx + 1 < questions.length) {
      setCurrentIdx(i => i + 1);
      setSelectedOption(null);
      setRevelation(false);
    } else {
      setFinished(true);
      onResult(score > questions.length / 2);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-40">
        <div className="w-12 h-12 border-4 border-[#7c1a1a] border-t-transparent rounded-full animate-spin mb-4" />
        <p className="serif text-xl italic text-stone-500">Preparing the arena...</p>
      </div>
    );
  }

  if (history.length < 3) {
    return (
      <div className="max-w-xl mx-auto text-center py-20 bg-white border border-stone-300 p-10">
        <h2 className="serif text-3xl mb-4">Archive Too Thin</h2>
        <p className="text-stone-500 mb-8">You need at least 3 historical translations to enter the Arena.</p>
        <div className="accent-bg h-1 w-20 mx-auto" />
      </div>
    );
  }

  if (finished) {
    return (
      <div className="max-w-xl mx-auto text-center py-20 bg-white border border-stone-300 p-10 animate-in zoom-in-95 duration-500">
        <h2 className="serif text-5xl mb-4">Arena Concluded</h2>
        <p className="text-stone-500 mb-8">You attained a score of {score} out of {questions.length}.</p>
        <p className="text-[#7c1a1a] font-bold text-2xl">+{score * 50} XP EARNED</p>
      </div>
    );
  }

  const q = questions[currentIdx];

  return (
    <div className="max-w-2xl mx-auto py-12 px-4">
      <div className="flex justify-between items-center mb-8">
        <span className="text-xs tracking-widest text-stone-400 uppercase font-bold">Question {currentIdx + 1} of {questions.length}</span>
        <div className="w-32 h-1 bg-stone-200">
          <div className="h-full bg-[#7c1a1a] transition-all" style={{ width: `${((currentIdx + 1) / questions.length) * 100}%` }} />
        </div>
      </div>

      <div className="bg-white border border-stone-300 p-10 shadow-sm mb-8">
        <h3 className="serif text-3xl mb-10 text-stone-900 leading-tight">{q.question}</h3>

        <div className="grid grid-cols-1 gap-4">
          {q.options.map((opt) => {
            const isCorrect = opt === q.correctAnswer;
            const isSelected = opt === selectedOption;

            let colorClass = "border-stone-200 hover:border-stone-400 text-stone-700";
            if (revelation) {
              if (isCorrect) colorClass = "border-green-500 bg-green-50 text-green-700";
              else if (isSelected) colorClass = "border-red-500 bg-red-50 text-red-700";
              else colorClass = "border-stone-100 text-stone-300 opacity-50";
            }

            return (
              <button
                key={opt}
                disabled={revelation}
                onClick={() => handleOptionSelect(opt)}
                className={`w-full text-left p-4 border transition-all duration-300 font-medium ${colorClass}`}
              >
                {opt}
              </button>
            );
          })}
        </div>

        {revelation && (
          <div className="mt-8 pt-8 border-t border-stone-100 animate-in slide-in-from-top-4">
            <span className="text-[10px] uppercase tracking-widest text-[#7c1a1a] block mb-2 font-bold">Lexicon Revelation</span>
            <p className="serif italic text-stone-600 mb-6">{q.explanation}</p>
            <button 
              onClick={nextQuestion}
              className="w-full accent-bg text-white py-4 font-bold tracking-widest uppercase hover:opacity-90 transition-opacity"
            >
              Continue Archival Test
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Arena;

import React from 'react';
import { LexicalEntry } from '../types';
import ResultCard from './ResultCard';

interface Props {
  history: LexicalEntry[];
}

const Archive: React.FC<Props> = ({ history }) => {
  if (history.length === 0) {
    return (
      <div className="max-w-4xl mx-auto py-40 text-center opacity-30">
        <svg className="mx-auto mb-6" xmlns="http://www.w3.org/2000/svg" width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10"/><path d="m9 12 2 2 4-4"/></svg>
        <p className="serif text-2xl italic">The archive is currently empty.</p>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto py-12 px-4">
      <div className="flex items-baseline justify-between mb-12 border-b border-stone-300 pb-4">
        <h2 className="serif text-4xl font-bold">The Archive</h2>
        <span className="text-xs uppercase tracking-widest text-stone-400">{history.length} Saved Inscriptions</span>
      </div>

      <div className="space-y-12">
        {history.map((entry) => (
          <ResultCard key={entry.id} entry={entry} />
        ))}
      </div>
    </div>
  );
};

export default Archive;

import React, { useState, useEffect, useMemo } from 'react';
import { AppMode, LexicalEntry, UserProfile } from './types';
import Dictionary from './components/Dictionary';
import Arena from './components/Arena';
import Archive from './components/Archive';
import XPProgress from './components/XPProgress';
import { RANKS } from './constants';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.DICTIONARY);
  const [history, setHistory] = useState<LexicalEntry[]>([]);
  const [autoAudio, setAutoAudio] = useState(() => localStorage.getItem('autoAudio') === 'true');
  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('lexProfile');
    return saved ? JSON.parse(saved) : {
      username: 'Scholar',
      xp: 0,
      rank: RANKS[0].title,
      searchCount: 0,
      arenaWins: 0
    };
  });

  // "Hot" In-memory cache
  const hotCache = useMemo(() => new Map<string, LexicalEntry>(), []);

  useEffect(() => {
    const savedHistory = localStorage.getItem('lexHistory');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    // Telegram integration
    if ((window as any).Telegram?.WebApp) {
      const tg = (window as any).Telegram.WebApp;
      tg.ready();
      tg.expand();
      if (tg.initDataUnsafe?.user?.username) {
        setProfile(p => ({ ...p, username: tg.initDataUnsafe.user.username }));
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('lexHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('lexProfile', JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem('autoAudio', String(autoAudio));
  }, [autoAudio]);

  const addEntry = (entry: LexicalEntry) => {
    setHistory(prev => [entry, ...prev].slice(0, 30));
    setProfile(p => ({ ...p, xp: p.xp + 10, searchCount: p.searchCount + 1 }));
    hotCache.set(`${entry.sourceWord}-${entry.sourceLang}-${entry.targetLang}`, entry);
  };

  const handleArenaResult = (won: boolean) => {
    if (won) {
      setProfile(p => ({ ...p, xp: p.xp + 250, arenaWins: p.arenaWins + 1 }));
    } else {
      setProfile(p => ({ ...p, xp: p.xp + 50 }));
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header Overlay */}
      <header className="sticky top-0 z-50 bg-stone-50/80 backdrop-blur-md border-b border-stone-200 px-6 py-4">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-6">
            <span 
              onClick={() => setMode(AppMode.DICTIONARY)}
              className="text-2xl font-bold tracking-tighter cursor-pointer hover:text-[#7c1a1a] transition-colors"
            >
              LEX.
            </span>
            <nav className="hidden md:flex gap-8 text-[10px] uppercase tracking-[0.2em] font-bold text-stone-500">
              <button 
                onClick={() => setMode(AppMode.DICTIONARY)} 
                className={`hover:text-[#7c1a1a] transition-colors ${mode === AppMode.DICTIONARY ? 'text-[#7c1a1a]' : ''}`}
              >
                Dictionary
              </button>
              <button 
                onClick={() => setMode(AppMode.ARENA)} 
                className={`hover:text-[#7c1a1a] transition-colors ${mode === AppMode.ARENA ? 'text-[#7c1a1a]' : ''}`}
              >
                The Arena
              </button>
              <button 
                onClick={() => setMode(AppMode.ARCHIVE)} 
                className={`hover:text-[#7c1a1a] transition-colors ${mode === AppMode.ARCHIVE ? 'text-[#7c1a1a]' : ''}`}
              >
                Archive
              </button>
            </nav>
          </div>

          <div className="flex items-center gap-6">
            <label className="flex items-center gap-2 cursor-pointer group">
              <span className="text-[9px] uppercase tracking-tighter text-stone-400 font-bold group-hover:text-stone-600 transition-colors">Auto-Audio</span>
              <input 
                type="checkbox" 
                checked={autoAudio} 
                onChange={() => setAutoAudio(!autoAudio)}
                className="w-3 h-3 accent-[#7c1a1a] cursor-pointer"
              />
            </label>
            <div className="flex flex-col items-end">
              <span className="text-[10px] font-bold text-[#7c1a1a]">{profile.xp} XP</span>
              <span className="text-[9px] uppercase tracking-widest text-stone-400">{profile.rank}</span>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 bg-stone-50">
        <div className="max-w-6xl mx-auto px-6 py-8">
          <XPProgress profile={profile} />

          {mode === AppMode.DICTIONARY && (
            <Dictionary onEntrySaved={addEntry} autoAudio={autoAudio} />
          )}

          {mode === AppMode.ARENA && (
            <Arena history={history} onResult={handleArenaResult} />
          )}

          {mode === AppMode.ARCHIVE && (
            <Archive history={history} />
          )}
        </div>
      </main>

      {/* Mobile Navigation */}
      <footer className="md:hidden sticky bottom-0 bg-stone-900 text-stone-400 border-t border-stone-800 px-8 py-4 flex justify-between items-center z-50">
         <button onClick={() => setMode(AppMode.DICTIONARY)} className={mode === AppMode.DICTIONARY ? 'text-white' : ''}>
           <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
         </button>
         <button onClick={() => setMode(AppMode.ARENA)} className={mode === AppMode.ARENA ? 'text-white' : ''}>
           <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14.5 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14.5 2z"/><polyline points="14 2 14 8 20 8"/></svg>
         </button>
         <button onClick={() => setMode(AppMode.ARCHIVE)} className={mode === AppMode.ARCHIVE ? 'text-white' : ''}>
           <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 19.5v-15A2.5 2.5 0 0 1 6.5 2H20v20H6.5a2.5 2.5 0 0 1-2.5-2.5z"/><path d="M8 7h6"/><path d="M8 11h8"/><path d="M8 15h6"/></svg>
         </button>
      </footer>
    </div>
  );
};

export default App;

