import React, { useState } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWord } from '../services/gemini';
import { speak } from '../services/tts';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const Dictionary: React.FC<Props> = ({ onEntrySaved, autoAudio, setAutoAudio, profile, history, onStartArena }) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    try {
      const entry = await translateWord(query, sourceLang, targetLang);
      setResult(entry);
      onEntrySaved(entry);
      if (autoAudio) {
        speak(entry.targetWord, entry.targetLang);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-12">
      {/* Stats and Toggles */}
      <div className="flex justify-between items-end">
        <div className="space-y-1">
          <span className="text-[10px] uppercase tracking-[0.2em] text-stone-400 font-bold">Lexical Ranking</span>
          <div className="flex items-baseline gap-2">
            <span className="text-2xl font-bold serif text-[#7c1a1a] leading-none">{profile.xp}</span>
            <span className="text-[10px] uppercase tracking-widest text-stone-400 font-bold">XP</span>
          </div>
        </div>

        <div className="flex items-center gap-12">
          {/* Language Selection - per screenshot */}
          <div className="flex items-center gap-3">
             <div className="flex border border-stone-200 bg-white">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button 
                    key={full}
                    onClick={() => setSourceLang(full)}
                    className={`px-3 py-2 text-[10px] font-bold tracking-widest border-r border-stone-100 last:border-r-0 transition-colors ${sourceLang === full ? 'bg-stone-50 text-black' : 'text-stone-300 hover:text-stone-500'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
             <svg className="text-stone-300" xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m17 2 4 4-4 4"/><path d="M3 11v-1a4 4 0 0 1 4-4h14"/><path d="m7 22-4-4 4-4"/><path d="M21 13v1a4 4 0 0 1-4 4H3"/></svg>
             <div className="flex border border-stone-200 bg-white">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button 
                    key={full}
                    onClick={() => setTargetLang(full)}
                    className={`px-3 py-2 text-[10px] font-bold tracking-widest border-r border-stone-100 last:border-r-0 transition-colors ${targetLang === full ? 'bg-stone-50 text-black' : 'text-stone-300 hover:text-stone-500'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
          </div>

          <div className="flex items-center gap-4">
            <span className="text-[10px] uppercase tracking-[0.2em] text-stone-400 font-bold">Auto-Pronounce</span>
            <button 
              onClick={() => setAutoAudio(!autoAudio)}
              className={`w-10 h-5 rounded-full relative transition-colors ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}
            >
              <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${autoAudio ? 'left-6' : 'left-1'}`} />
            </button>
          </div>
        </div>
      </div>

      {/* Search Input - per screenshot */}
      <form onSubmit={handleSearch} className="relative group">
        <div className="bg-white border border-stone-200 shadow-[0_4px_20px_-10px_rgba(0,0,0,0.05)] px-10 py-8 flex items-center gap-6">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search for an inscription..."
            className="flex-1 text-5xl serif bg-transparent outline-none text-stone-900 placeholder:text-stone-200 lowercase"
          />
          <button 
            type="submit"
            disabled={loading}
            className="text-stone-300 hover:text-[#7c1a1a] transition-all transform active:scale-95"
          >
            {loading ? (
              <div className="w-10 h-10 border-2 border-[#7c1a1a] border-t-transparent rounded-full animate-spin" />
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
            )}
          </button>
        </div>
      </form>

      {/* Result Card - per screenshot */}
      {result && <ResultCard entry={result} />}

      {/* History Grid - per screenshot */}
      <div className="pt-20">
        <div className="flex justify-between items-baseline mb-8 border-l-[3px] border-[#7c1a1a]/10 pl-6">
          <h2 className="text-[10px] uppercase tracking-[0.4em] text-stone-400 font-bold">Linguistic History</h2>
          <button 
            onClick={onStartArena}
            className="bg-[#7c1a1a] text-white px-8 py-4 flex items-center gap-3 shadow-[0_10px_30px_-10px_rgba(124,26,26,0.3)] hover:translate-y-[-2px] transition-all"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
            <span className="text-[10px] uppercase tracking-[0.3em] font-bold">Start Arena</span>
          </button>
        </div>
        <HistoryGrid history={history} />
      </div>
    </div>
  );
};

export default Dictionary;

import React from 'react';
import { LexicalEntry, Language } from '../types';
import { speak } from '../services/tts';

interface Props {
  entry: LexicalEntry;
}

const ResultCard: React.FC<Props> = ({ entry }) => {
  const showCefr = (lang: Language) => lang !== 'Uzbek';

  return (
    <div className="bg-white border border-stone-200 p-16 shadow-[0_20px_50px_-20px_rgba(0,0,0,0.04)] animate-in fade-in slide-in-from-bottom-6 duration-700">
      {/* Main Translation View */}
      <div className="flex items-start justify-between mb-24">
        {/* Source Word */}
        <div className="flex-1">
          <div className="flex items-center gap-4 mb-4">
            <h1 className="text-9xl serif font-bold tracking-tighter lowercase leading-[0.8]">
              {entry.sourceWord}
            </h1>
            <div className="flex flex-col gap-2">
              {showCefr(entry.sourceLang) && (
                <div className="bg-stone-900 text-white text-[9px] px-3 py-1 font-black uppercase tracking-widest whitespace-nowrap">
                  Level: {entry.cefrSource}
                </div>
              )}
              <button onClick={() => speak(entry.sourceWord, entry.sourceLang)} className="text-stone-200 hover:text-stone-400 transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M11 5L6 9H2v6h4l5 4V5z"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/></svg>
