            </div>
          </div>

          <div className="flex gap-6 mt-8">
            <div className="bg-stone-50 px-3 py-1 text-[10px] uppercase tracking-widest font-bold text-stone-500">{entry.partOfSpeech}</div>
            {entry.gender && (
              <div className="text-[10px] uppercase tracking-widest font-bold text-stone-400 py-1">Gender: {entry.gender}</div>
            )}
            {entry.plural && (
              <div className="text-[10px] uppercase tracking-widest font-bold text-stone-400 py-1">Plural: {entry.plural}</div>
            )}
          </div>
        </div>

