import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function translateWord(
  word: string, 
  sourceLang: Language, 
  targetLang: Language
): Promise<LexicalEntry> {
  const prompt = `Act as a master philologist. Translate the word or phrase "${word}" from ${sourceLang} to ${targetLang}. 
    Requirements:
    1. If German is involved, include gender (der/die/das), plural forms, and the CEFR level (A1-C2).
    2. For Uzbek, use modern Latin script.
    3. Provide a 'linguisticAnalysis' field explaining the etymology or specific cultural usage.
    4. Provide 3 high-quality examples from literature or cinema with specific source attribution.
    5. Provide at least 3 alternatives for the target word.
    Format the response as JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          targetWord: { type: Type.STRING },
          partOfSpeech: { type: Type.STRING },
          gender: { type: Type.STRING },
          plural: { type: Type.STRING },
          phoneticSource: { type: Type.STRING },
          phoneticTarget: { type: Type.STRING },
          cefrSource: { type: Type.STRING },
          cefrTarget: { type: Type.STRING },
          linguisticAnalysis: { type: Type.STRING },
          synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
          alternatives: { type: Type.ARRAY, items: { type: Type.STRING } },
          examples: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                translation: { type: Type.STRING },
                context: { type: Type.STRING }
              },
              required: ["text", "translation", "context"]
            }
          }
        },
        required: ["targetWord", "partOfSpeech", "linguisticAnalysis", "synonyms", "alternatives", "examples"]
      }
    }
  });

  const rawData = JSON.parse(response.text);

  return {
    id: crypto.randomUUID(),
    sourceWord: word,
    sourceLang,
    targetWord: rawData.targetWord,
    targetLang,
    partOfSpeech: rawData.partOfSpeech,
    gender: rawData.gender,
    plural: rawData.plural,
    phoneticSource: rawData.phoneticSource || "",
    phoneticTarget: rawData.phoneticTarget || "",
    cefrSource: rawData.cefrSource || "A1",
    cefrTarget: rawData.cefrTarget || "A1",
    annotations: rawData.linguisticAnalysis,
    etymologyNotes: rawData.linguisticAnalysis,
    synonyms: rawData.synonyms,
    alternatives: rawData.alternatives,
    examples: rawData.examples,
    timestamp: Date.now()
  };
}

export async function generateQuiz(entries: LexicalEntry[]) {
  const words = entries.map(e => `${e.sourceWord} -> ${e.targetWord}`).join(", ");
  const prompt = `Create a challenging 5-question multiple choice quiz based on these words: ${words}. 
    Focus on meaning and context. Return JSON only. Each question must have one correct answer and three distractors.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            correctAnswer: { type: Type.STRING },
            options: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            explanation: { type: Type.STRING }
          },
          required: ["question", "correctAnswer", "options", "explanation"]
        }
      }
    }
  });

  return JSON.parse(response.text);
}

