          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search for an inscription..."
            className="flex-1 text-6xl md:text-8xl serif bg-transparent outline-none text-stone-900 placeholder:text-stone-100 lowercase font-medium tracking-tighter"
          />
          <button 
            type="submit"
            disabled={loading}
            className="text-stone-200 hover:text-[#7c1a1a] transition-all transform active:scale-90 hover:scale-110"
