import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function translateWord(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const prompt = `Act as a master philologist. Translate the word or phrase "${query}" from ${sourceLanguage} to ${targetLanguage}.
Requirements:
1. If German is involved, include gender (der/die/das), plural forms, and the CEFR level (A1-C2).
2. For Uzbek, use modern Latin script.
3. Provide a 'notes' field in grammar explaining the etymology or specific cultural usage of the source term.
4. Provide 3 high-quality examples from literature or cinema.
Return JSON only.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          mainTranslation: { type: Type.STRING },
          sourceLevel: { type: Type.STRING, description: 'CEFR level e.g. A2, B1' },
          targetLevel: { type: Type.STRING },
          alternatives: { type: Type.ARRAY, items: { type: Type.STRING } },
          sourceSynonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
          grammar: {
            type: Type.OBJECT,
            properties: {
              partOfSpeech: { type: Type.STRING },
              gender: { type: Type.STRING, description: 'German specific (der/die/das)' },
              plural: { type: Type.STRING },
              notes: { type: Type.STRING, description: 'Etymology or cultural context' }
            },
            required: ["partOfSpeech", "notes"]
          },
          examples: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                translation: { type: Type.STRING },
                sourceTitle: { type: Type.STRING },
                sourceType: { type: Type.STRING, enum: ['Literature', 'Cinema', 'History', 'General'] }
              },
              required: ["text", "translation", "sourceTitle", "sourceType"]
            }
          }
        },
        required: ["term", "mainTranslation", "alternatives", "sourceSynonyms", "grammar", "examples"]
      }
    }
  });

  const rawData = JSON.parse(response.text);

  return {
    id: crypto.randomUUID(),
    term: rawData.term,
    mainTranslation: rawData.mainTranslation,
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    sourceLevel: rawData.sourceLevel,
    targetLevel: rawData.targetLevel,
    alternatives: rawData.alternatives,
    sourceSynonyms: rawData.sourceSynonyms,
    grammar: rawData.grammar,
    examples: rawData.examples,
    timestamp: Date.now()
  };
}

export async function generateQuiz(entries: LexicalEntry[]) {
  const words = entries.map(e => `${e.term} -> ${e.mainTranslation}`).join(", ");
  const prompt = `Create a challenging 5-question multiple choice quiz based on these words: ${words}. Focus on meaning and context. Return JSON only. Each question must have one correct answer and three distractors.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            correctAnswer: { type: Type.STRING },
            options: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            explanation: { type: Type.STRING }
          },
          required: ["question", "correctAnswer", "options", "explanation"]
        }
      }
    }
  });

  return JSON.parse(response.text);
}

