  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const Dictionary: React.FC<Props> = ({ onEntrySaved, autoAudio, setAutoAudio, profile, history, onStartArena }) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setResult(null);

    try {
      // Simulation of Multi-Tier Architecture lookup
      const lookupKey = `${query.toLowerCase()}-${sourceLang}-${targetLang}`;

      // 1. Tier 2/3: Check local "Hot Cache" / "Database" (History)
      const dbLookup = new Promise<LexicalEntry | null>((resolve) => {
        const found = history.find(h => 
          h.term.toLowerCase() === query.toLowerCase() && 
          h.sourceLang === sourceLang && 
          h.targetLang === targetLang
        );
        // Simulate a slight DB delay (indexed lookup)
        setTimeout(() => resolve(found || null), 200);
      });

      // 2. Tier 4: Gemini AI (Philologist Engine)
      const aiLookup = translateWord(query, sourceLang, targetLang);

      // Race condition logic: Database lookup (500ms timeout) vs Gemini API
      // If DB returns a result before 500ms, use it.
      // Otherwise wait for AI.
      const entry = await Promise.race([
        dbLookup.then(res => {
          if (res) return res;
          return new Promise<never>(() => {}); // Don't resolve if not found, let AI finish
        }),
        aiLookup,
        new Promise<null>((_, reject) => setTimeout(() => reject('timeout'), 500)).catch(() => null)
      ]);

      let finalEntry = entry;
      if (!finalEntry) {
        // If race timed out or DB failed, wait for AI result specifically
        finalEntry = await aiLookup;
      }

      setResult(finalEntry);
      onEntrySaved(finalEntry);

      if (autoAudio) {
        speak(finalEntry.mainTranslation, finalEntry.targetLang);
      }
    } catch (err) {
      console.error("Philologist Engine Error:", err);
    } finally {
      setLoading(false);
    }
