                    onClick={() => setSourceLang(full)}
                    className={`px-5 py-3 text-[11px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-50 text-stone-900' : 'text-stone-300 hover:text-stone-500'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
             <button 
                type="button" 
                onClick={() => { const tmp = sourceLang; setSourceLang(targetLang); setTargetLang(tmp); }}
                className="text-stone-300 hover:text-[#7c1a1a] transition-colors p-2"
              >
               <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m17 2 4 4-4 4"/><path d="M3 11v-1a4 4 0 0 1 4-4h14"/><path d="m7 22-4-4 4-4"/><path d="M21 13v1a4 4 0 0 1-4 4H3"/></svg>
             </button>
             <div className="flex border border-stone-200 bg-white shadow-sm overflow-hidden">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button 
                    key={full}
                    type="button"
                    onClick={() => setTargetLang(full)}
                    className={`px-5 py-3 text-[11px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-stone-50 text-stone-900' : 'text-stone-300 hover:text-stone-500'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
          </div>

          <div className="flex items-center gap-6">
            <span className="text-[11px] uppercase tracking-[0.3em] text-stone-400 font-black">Auto-Pronounce</span>
