import React, { useState, useEffect } from 'react';
import { LexicalEntry } from '../types';
import { generateQuiz } from '../services/gemini';

interface Props {
  history: LexicalEntry[];
  onResult: (score: number) => void;
}

interface Question {
  question: string;
  correctAnswer: string;
  options: string[];
  explanation: string;
}

const Arena: React.FC<Props> = ({ history, onResult }) => {
  const [questions, setQuestions] = useState<Question[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [score, setScore] = useState(0);
  const [loading, setLoading] = useState(true);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [revelation, setRevelation] = useState(false);
  const [finished, setFinished] = useState(false);

  useEffect(() => {
    const loadQuiz = async () => {
      if (history.length < 3) {
        setLoading(false);
        return;
      }
      try {
        const data = await generateQuiz(history.slice(0, 10));
        setQuestions(data);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    loadQuiz();
  }, [history]);

  const handleOptionSelect = (option: string) => {
    if (revelation) return;

    setSelectedOption(option);
    setRevelation(true);

    const isCorrect = option === questions[currentIdx].correctAnswer;
    if (isCorrect) setScore(s => s + 1);

    if ((window as any).Telegram?.WebApp) {
      (window as any).Telegram.WebApp.HapticFeedback.notificationOccurred(isCorrect ? 'success' : 'error');
    }
  };

  const nextQuestion = () => {
    if (currentIdx + 1 < questions.length) {
      setCurrentIdx(i => i + 1);
      setSelectedOption(null);
      setRevelation(false);
    } else {
      setFinished(true);
      onResult(score);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-40">
        <div className="w-16 h-16 border-[3px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin mb-8" />
        <p className="serif text-2xl italic text-stone-300">Summoning the Archival Test...</p>
      </div>
    );
  }

  if (history.length < 3) {
    return (
      <div className="max-w-2xl mx-auto text-center py-20 bg-white border border-stone-100 p-16 shadow-xl">
        <h2 className="serif text-5xl font-black mb-6 lowercase">Archive Too Shallow</h2>
        <p className="text-stone-400 text-lg mb-10 leading-relaxed font-light serif italic">You require at least three historical inscriptions to initiate a lexical trial in the Arena.</p>
        <div className="bg-[#7c1a1a] h-1 w-24 mx-auto" />
      </div>
    );
  }

  if (finished) {
    return (
      <div className="max-w-3xl mx-auto text-center py-20 bg-white border border-stone-100 p-20 shadow-2xl animate-in zoom-in-95 duration-700">
        <h2 className="serif text-7xl font-black mb-8 lowercase">Arena Concluded</h2>
        <p className="text-stone-300 text-xl mb-12 serif italic">Your archival knowledge has yielded {score} correct revelations out of {questions.length}.</p>
        <div className="space-y-4">
          <p className="text-[#7c1a1a] font-black text-4xl tracking-tighter">+{score * 20} XP ACCRUED</p>
          <div className="bg-stone-50 py-4 px-8 inline-block border border-stone-100">
             <span className="text-[11px] uppercase tracking-[0.4em] text-stone-400 font-black">Archive Synchronization: COMPLETE</span>
          </div>
        </div>
      </div>
    );
  }

  const q = questions[currentIdx];

  return (
    <div className="max-w-[1000px] mx-auto py-16 px-4">
      <div className="flex justify-between items-end mb-16 border-l-[4px] border-[#7c1a1a] pl-8">
        <div>
          <span className="text-[11px] uppercase tracking-[0.5em] text-stone-400 font-black block mb-1">Trial In Progress</span>
          <span className="text-stone-300 serif italic text-xl">Manifestation {currentIdx + 1} of {questions.length}</span>
        </div>
        <div className="w-64 h-[1px] bg-stone-100 relative">
          <div className="absolute top-0 left-0 h-full bg-[#7c1a1a] transition-all duration-700" style={{ width: `${((currentIdx + 1) / questions.length) * 100}%` }} />
        </div>
      </div>

      <div className="bg-white border border-stone-100 p-16 md:p-24 shadow-[0_40px_100px_-20px_rgba(0,0,0,0.05)]">
        <h3 className="serif text-5xl md:text-6xl font-medium mb-16 text-stone-900 leading-[1.1] tracking-tight">{q.question}</h3>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {q.options.map((opt) => {
            const isCorrect = opt === q.correctAnswer;
            const isSelected = opt === selectedOption;

            let colorClass = "border-stone-100 hover:border-stone-300 text-stone-600";
            if (revelation) {
              if (isCorrect) colorClass = "border-green-400 bg-green-50/30 text-green-700 shadow-sm";
              else if (isSelected) colorClass = "border-red-400 bg-red-50/30 text-red-700 shadow-sm";
              else colorClass = "border-stone-50 text-stone-200 opacity-40";
            }

            return (
              <button
                key={opt}
                disabled={revelation}
                onClick={() => handleOptionSelect(opt)}
                className={`w-full text-left p-8 border transition-all duration-500 serif text-xl md:text-2xl ${colorClass}`}
              >
                {opt}
              </button>
            );
          })}
        </div>

        {revelation && (
          <div className="mt-20 pt-16 border-t border-stone-50 animate-in slide-in-from-top-8 duration-700">
            <span className="text-[11px] uppercase tracking-[0.5em] text-[#7c1a1a] block mb-6 font-black">Philologist Revelation</span>
            <p className="serif italic text-2xl text-stone-500 mb-12 leading-relaxed font-light">{q.explanation}</p>
            <button 
              onClick={nextQuestion}
              className="w-full bg-[#7c1a1a] text-white py-8 text-[11px] font-black tracking-[0.5em] uppercase hover:bg-[#8d2020] transition-all shadow-[0_20px_40px_-10px_rgba(124,26,26,0.3)]"
            >
              Continue Lexical Pursuit
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

