  }, []);

  useEffect(() => {
    localStorage.setItem('lexHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('lexProfile', JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem('autoAudio', String(autoAudio));
  }, [autoAudio]);

  const addEntry = (entry: LexicalEntry) => {
    setHistory(prev => {
      const filtered = prev.filter(p => p.term.toLowerCase() !== entry.term.toLowerCase());
      return [entry, ...filtered].slice(0, 30);
    });
    // 10 XP per search as per brief
    setProfile(p => {
      const newXp = p.xp + 10;
      const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
      return { 
        ...p, 
        xp: newXp, 
        rank: newRank.title,
        searchCount: p.searchCount + 1 
      };
    });
    hotCache.set(`${entry.term.toLowerCase()}-${entry.sourceLang}-${entry.targetLang}`, entry);
  };

  const handleArenaResult = (correctCount: number) => {
    // 20 XP per correct answer as per brief
    const earnedXp = correctCount * 20;
    setProfile(p => {
      const newXp = p.xp + earnedXp;
      const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
      return { 
        ...p, 
        xp: newXp, 
        rank: newRank.title,
        arenaWins: p.arenaWins + 1 
      };
    });
  };

  return (
    <div className="min-h-screen bg-[#fcfcfb] flex flex-col selection:bg-[#7c1a1a]/10 selection:text-[#7c1a1a]">
      <header className="px-10 py-8 max-w-[1400px] mx-auto w-full flex items-center justify-between">
        <div className="flex items-center gap-6">
          <span 
            onClick={() => setMode(AppMode.DICTIONARY)}
            className="text-4xl serif font-bold tracking-tight cursor-pointer text-[#7c1a1a] transition-colors"
          >
            LEX.
          </span>
          <div className="h-6 w-[1px] bg-stone-200"></div>
          <span className="text-[10px] uppercase tracking-[0.4em] text-stone-400 font-semibold pt-1">
            Polyglot Insight Engine
          </span>
        </div>

        <nav className="flex gap-10 text-[10px] uppercase tracking-[0.2em] font-bold text-stone-500">
          <button 
            onClick={() => setMode(AppMode.DICTIONARY)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 ${mode === AppMode.DICTIONARY ? 'border-[#7c1a1a] text-[#7c1a1a]' : 'border-transparent'}`}
          >
            Dictionary
          </button>
          <button 
            onClick={() => setMode(AppMode.ARENA)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 ${mode === AppMode.ARENA ? 'border-[#7c1a1a] text-[#7c1a1a]' : 'border-transparent'}`}
          >
            The Arena
          </button>
          <button 
            onClick={() => setMode(AppMode.ARCHIVE)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 ${mode === AppMode.ARCHIVE ? 'border-[#7c1a1a] text-[#7c1a1a]' : 'border-transparent'}`}
          >
            History
          </button>
        </nav>
      </header>

      <main className="flex-1">
        <div className="max-w-[1400px] mx-auto px-10">
          {mode === AppMode.DICTIONARY && (
            <Dictionary 
              onEntrySaved={addEntry} 
              autoAudio={autoAudio} 
              setAutoAudio={setAutoAudio}
              profile={profile}
              history={history}
              onStartArena={() => setMode(AppMode.ARENA)}
            />
          )}

          {mode === AppMode.ARENA && (
            <Arena history={history} onResult={handleArenaResult} />
          )}

          {mode === AppMode.ARCHIVE && (
            <Archive history={history} />
          )}
        </div>
      </main>

      <footer className="py-12 text-center">
        <div className="max-w-[1400px] mx-auto px-10 border-t border-stone-100 pt-8 flex justify-between items-center text-[10px] uppercase tracking-widest text-stone-300 font-bold">
          <span>&copy; 2025 Lexicon Archive</span>
          <span className="text-stone-400">{profile.rank} • LVL {Math.floor(profile.xp / 1000) + 1}</span>
        </div>
      </footer>
    </div>
  );
};

