interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const Dictionary: React.FC<Props> = ({ onEntrySaved, autoAudio, setAutoAudio, profile, history, onStartArena }) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);

  // In-memory Hot Cache (Tier 2) derived from history
  const hotCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();
    history.forEach(entry => {
      const key = `${entry.term.toLowerCase()}-${entry.sourceLang}-${entry.targetLang}`;
      if (!cache.has(key)) cache.set(key, entry);
    });
    return cache;
  }, [history]);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    const normalizedQuery = query.trim().toLowerCase();
    if (!normalizedQuery) return;

    // TIER 1 & 2: Instant Cache/History Lookup
    const cacheKey = `${normalizedQuery}-${sourceLang}-${targetLang}`;
    const cachedResult = hotCache.get(cacheKey);

    if (cachedResult) {
      setResult(cachedResult);
      if (autoAudio) {
        speak(cachedResult.mainTranslation, cachedResult.targetLang);
      }
      return; // Exit early - No AI call needed
    }

    // TIER 3: AI Philologist Engine (Only if not found)
    setLoading(true);
    setResult(null);

    try {
      const finalEntry = await translateWord(query, sourceLang, targetLang);

      setResult(finalEntry);
      onEntrySaved(finalEntry);

      if (autoAudio) {
        speak(finalEntry.mainTranslation, finalEntry.targetLang);
      }
    } catch (err) {
      console.error("Philologist Engine Error:", err);
      // Optional: Add user-friendly error toast here
    } finally {
      setLoading(false);
    }
  };

  const swapLanguages = () => {
    const prevSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(prevSource);
  };

  return (
    <div className="space-y-16">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-10">
        <div className="space-y-3">
