interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const Dictionary: React.FC<Props> = ({ onEntrySaved, autoAudio, setAutoAudio, profile, history, onStartArena }) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);

  // Unified Fast-Access Cache (Tier 1 & 2)
  const unifiedCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();

    // Add History
    history.forEach(entry => {
      const key = `${entry.term.toLowerCase()}-${entry.sourceLang}-${entry.targetLang}`;
      cache.set(key, entry);
    });

    // Add Static Seed (Tier 0)
    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const fullEntry: LexicalEntry = {
        id: `seed-${key}`,
        term: entry.term!,
        mainTranslation: entry.mainTranslation!,
        sourceLang: key.split('-')[1] as Language,
        targetLang: key.split('-')[2] as Language,
        alternatives: entry.alternatives || [],
        sourceSynonyms: entry.sourceSynonyms || [],
        grammar: entry.grammar as any,
        examples: entry.examples as any,
        timestamp: Date.now()
      };
      cache.set(key, fullEntry);
    });

    return cache;
  }, [history]);

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    const normalizedQuery = query.trim().toLowerCase();
    if (!normalizedQuery) return;

    const cacheKey = `${normalizedQuery}-${sourceLang}-${targetLang}`;
    const fastHit = unifiedCache.get(cacheKey);

    // INSTANT RESULT (Tier 0, 1, 2)
    if (fastHit) {
      setResult(fastHit);
      if (autoAudio) speak(fastHit.mainTranslation, fastHit.targetLang);
      return;
    }

    // AI FALLBACK (Tier 3)
    setLoading(true);
    setResult(null);

    try {
      const finalEntry = await translateWord(query, sourceLang, targetLang);
      setResult(finalEntry);
      onEntrySaved(finalEntry);
      if (autoAudio) speak(finalEntry.mainTranslation, finalEntry.targetLang);
    } catch (err) {
      console.error("Philologist Engine Error:", err);
    } finally {
