                    onClick={() => setTargetLang(full)}
                    className={`px-5 py-3 text-[11px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-stone-50 text-stone-900' : 'text-stone-300 hover:text-stone-500'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
          </div>

          <div className="flex items-center gap-6">
            <span className="text-[11px] uppercase tracking-[0.3em] text-stone-400 font-black">Auto-Pronounce</span>
            <button 
              onClick={() => setAutoAudio(!autoAudio)}
              className={`w-12 h-6 rounded-full relative transition-all duration-300 p-1 ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}
            >
              <div className={`w-4 h-4 bg-white rounded-full transition-all shadow-md ${autoAudio ? 'ml-6' : 'ml-0'}`} />
            </button>
          </div>
        </div>
      </div>

      <form onSubmit={handleSearch} className="relative w-full max-w-[1400px]">
        <div className="bg-white border border-stone-100 shadow-[0_25px_100px_-20px_rgba(0,0,0,0.06)] px-12 md:px-20 py-12 md:py-16 flex items-center gap-10 hover:shadow-[0_35px_120px_-20px_rgba(0,0,0,0.08)] transition-all">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search for an inscription..."
            className="flex-1 text-6xl md:text-8xl serif bg-transparent outline-none text-stone-900 placeholder:text-stone-100 lowercase font-medium tracking-tighter"
          />
          <button 
            type="submit"
            disabled={loading}
            className="text-stone-200 hover:text-[#7c1a1a] transition-all transform active:scale-90 hover:scale-110"
          >
            {loading ? (
              <div className="w-16 h-16 border-[3px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin" />
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" width="84" height="84" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
            )}
          </button>
        </div>
      </form>

      <div className="min-h-[200px]">
        {loading && (
          <div className="bg-white border border-stone-100 p-20 animate-pulse space-y-12">
            <div className="flex justify-between items-end">
              <div className="h-24 w-64 bg-stone-50" />
              <div className="h-24 w-64 bg-stone-50" />
            </div>
            <div className="h-32 w-full bg-stone-50" />
            <div className="grid grid-cols-2 gap-12">
               <div className="h-20 bg-stone-50" />
               <div className="h-20 bg-stone-50" />
            </div>
          </div>
        )}
        {result && !loading && <ResultCard entry={result} />}
      </div>

      <div className="pt-32">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-10 mb-16">
          <div className="border-l-[4px] border-[#7c1a1a] pl-10 py-2">
            <h2 className="text-[11px] uppercase tracking-[0.5em] text-stone-400 font-black mb-1">Linguistic History</h2>
            <p className="text-stone-300 text-[10px] uppercase tracking-[0.2em] font-medium">Archive Persistence: ACTIVE</p>
          </div>
          <button 
            onClick={onStartArena}
            className="group relative bg-[#7c1a1a] text-white px-10 py-5 flex items-center gap-4 shadow-[0_20px_50px_-10px_rgba(124,26,26,0.4)] hover:shadow-[0_30px_60px_-10px_rgba(124,26,26,0.6)] hover:-translate-y-1 transition-all overflow-hidden"
          >
            <div className="absolute inset-0 bg-white/5 group-hover:bg-white/10 transition-colors" />
            <svg className="group-hover:rotate-12 transition-transform" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
            <span className="text-[11px] uppercase tracking-[0.4em] font-black relative">Start Arena</span>
          </button>
        </div>
        <HistoryGrid history={history} />
      </div>
    </div>
  );
};

export default Dictionary;

import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";
import { VOICE_MAPPING } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// In-memory audio buffer cache (Tier 2 for Audio)
const audioBufferCache = new Map<string, AudioBuffer>();

function decode(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export async function speak(text: string, lang: Language) {
  try {
    const cacheKey = `${text}-${lang}`;
    const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    // FAST HIT: Return cached buffer instantly
    if (audioBufferCache.has(cacheKey)) {
      const source = audioCtx.createBufferSource();
      source.buffer = audioBufferCache.get(cacheKey)!;
      source.connect(audioCtx.destination);
      source.start();
      return;
    }

    const voiceName = VOICE_MAPPING[lang] || 'Puck';
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      audioCtx,
      24000,
      1
    );

    // Save to cache for next time
    audioBufferCache.set(cacheKey, audioBuffer);

    const source = audioCtx.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(audioCtx.destination);
    source.start();
  } catch (error) {
    console.error("TTS Failed:", error);
  }
}
